instruction:
You are helping create a new feature in a Flutter app that follows Clean Architecture.

When the user provides a feature name:

1. Create the feature directory structure under `lib/features/<feature_name>/`:
   - `domain/entities/` - For business entities (*.entity.dart with Freezed)
   - `domain/repositories/` - For repository interfaces (*.repository.dart)
   - `data/datasources/remote/` - For remote data sources (*_remote_datasource.dart)
   - `data/repositories/` - For repository implementations (*_impl.repository.dart)
   - `presentation/screens/` - For screen widgets (*.screen.dart)
   - `presentation/widgets/` - For reusable widgets (*.widget.dart)
   - `presentation/provider/` - For Riverpod providers (*.provider.dart)

2. Create initial files:
   - A basic entity in `domain/entities/<feature_name>.entity.dart` using Freezed:
     ```dart
     import 'package:freezed_annotation/freezed_annotation.dart';

     part '<feature_name>.entity.freezed.dart';
     part '<feature_name>.entity.g.dart';

     @freezed
     class <FeatureName>Entity with _$<FeatureName>Entity {
       const factory <FeatureName>Entity({
         required String id,
       }) = _<FeatureName>Entity;

       factory <FeatureName>Entity.fromJson(Map<String, dynamic> json) => _$<FeatureName>EntityFromJson(json);
     }
     ```

   - A repository interface in `domain/repositories/<feature_name>.repository.dart`:
     ```dart
     import 'package:user_app/features/<feature_name>/domain/entities/<feature_name>.entity.dart';

     abstract class <FeatureName>Repository {
       Future<List<<FeatureName>Entity>> getAll();
       Future<<FeatureName>Entity> getById(String id);
     }
     ```

   - A data source in `data/datasources/remote/<feature_name>_remote_datasource.dart` with interface, implementation, and mock:
     ```dart
     import 'package:user_app/features/<feature_name>/domain/entities/<feature_name>.entity.dart';

     // Interface
     abstract class <FeatureName>RemoteDataSource {
       Future<List<<FeatureName>Entity>> fetchAll();
     }

     // Implementation
     class <FeatureName>RemoteDataSourceImpl implements <FeatureName>RemoteDataSource {
       // TODO: Inject API client

       @override
       Future<List<<FeatureName>Entity>> fetchAll() async {
         // TODO: Implement API call
         throw UnimplementedError();
       }
     }

     // Mock
     class <FeatureName>RemoteDataSourceMock implements <FeatureName>RemoteDataSource {
       @override
       Future<List<<FeatureName>Entity>> fetchAll() async {
         await Future.delayed(const Duration(seconds: 1));
         return [];
       }
     }
     ```

   - A repository implementation in `data/repositories/<feature_name>_impl.repository.dart`:
     ```dart
     import 'package:user_app/features/<feature_name>/domain/entities/<feature_name>.entity.dart';
     import 'package:user_app/features/<feature_name>/domain/repositories/<feature_name>.repository.dart';
     import 'package:user_app/features/<feature_name>/data/datasources/remote/<feature_name>_remote_datasource.dart';

     class <FeatureName>RepositoryImpl implements <FeatureName>Repository {
       final <FeatureName>RemoteDataSource _remoteDataSource;

       <FeatureName>RepositoryImpl(this._remoteDataSource);

       @override
       Future<List<<FeatureName>Entity>> getAll() async {
         return await _remoteDataSource.fetchAll();
       }

       @override
       Future<<FeatureName>Entity> getById(String id) async {
         throw UnimplementedError();
       }
     }
     ```

   - A basic screen in `presentation/screens/<feature_name>.screen.dart`:
     ```dart
     import 'package:flutter/material.dart';
     import 'package:flutter_riverpod/flutter_riverpod.dart';

     class <FeatureName>Screen extends ConsumerWidget {
       const <FeatureName>Screen({super.key});

       @override
       Widget build(BuildContext context, WidgetRef ref) {
         return Scaffold(
           appBar: AppBar(
             title: Text('<Feature Name>', style: Theme.of(context).textTheme.titleLarge),
           ),
           body: Center(
             child: Text('<Feature Name> Screen', style: Theme.of(context).textTheme.bodyMedium),
           ),
         );
       }
     }
     ```

   - A Riverpod provider file in `presentation/provider/<feature_name>.provider.dart`:
     ```dart
     import 'package:riverpod_annotation/riverpod_annotation.dart';
     import 'package:user_app/features/<feature_name>/domain/repositories/<feature_name>.repository.dart';
     import 'package:user_app/features/<feature_name>/data/repositories/<feature_name>_impl.repository.dart';
     import 'package:user_app/features/<feature_name>/data/datasources/remote/<feature_name>_remote_datasource.dart';

     part '<feature_name>.provider.g.dart';

     @riverpod
     <FeatureName>Repository <feature_name>Repository(<FeatureName>RepositoryRef ref) {
       // Switch between mock and real implementation
       final dataSource = <FeatureName>RemoteDataSourceMock();
       return <FeatureName>RepositoryImpl(dataSource);
     }
     ```

3. After creating files, remind the user to:
   - Run `dart run build_runner build --delete-conflicting-outputs` to generate code
   - Add routing if needed in `lib/router/routes.dart`

4. Convert <feature_name> to snake_case and <FeatureName> to PascalCase appropriately.

Always follow the project's Clean Architecture pattern and naming conventions.
